    20→}
    21→
    22→export function findEntryNodes(def: WorkflowDefinition): WorkflowNode[] {
    23→  const targets = new Set(def.edges.map((e) => e.target));
    24→  return def.nodes.filter((n) => !targets.has(n.id));
    25→}
    26→
    27→export function getSuccessors(
    28→  def: WorkflowDefinition,
    29→  nodeId: string,
    30→  port: string,
    31→): WorkflowNode[] {
    32→  const edgesFromPort = def.edges.filter((e) => e.source === nodeId && e.sourcePort === port);
    33→  return edgesFromPort
    34→    .map((e) => def.nodes.find((n) => n.id === e.target))
    35→    .filter((n): n is WorkflowNode => n != null);
    36→}
    37→
    38→export async function startWorkflowExecution(
    39→  workflow: Workflow,
    40→  triggerData: unknown,
    41→): Promise<string> {
    42→  const runId = crypto.randomUUID();
    43→  createWorkflowRun({ id: runId, workflowId: workflow.id, triggerData });
    44→  const ctx: Record<string, unknown> = { trigger: triggerData };
    45→  const entryNodes = findEntryNodes(workflow.definition);
    46→  await walkDag(workflow.definition, runId, ctx, entryNodes);
    47→  return runId;
    48→}
    49→
    50→export async function walkDag(
    51→  def: WorkflowDefinition,
    52→  runId: string,
    53→  ctx: Record<string, unknown>,
    54→  startNodes: WorkflowNode[],
    55→): Promise<void> {
    56→  const visited = new Set<string>();
    57→  const queue = [...startNodes];
    58→
    59→  while (queue.length > 0) {
    60→    const node = queue.shift()!;
    61→
    62→    // Cycle guard: if we've already visited this node, stop traversal
    63→    if (visited.has(node.id)) continue;
    64→    visited.add(node.id);
    65→
    66→    const stepId = crypto.randomUUID();
    67→    createWorkflowRunStep({
    68→      id: stepId,
    69→      runId,
    70→      nodeId: node.id,
    71→      nodeType: node.type,
    72→      input: ctx,
    73→    });
    74→
    75→    try {
    76→      const result = await executeNode(node, ctx, runId, stepId);
    77→
    78→      if (result.mode === "async") {
    79→        // Async node: pause the run. Step stays as 'waiting'.
    80→        updateWorkflowRunStep(stepId, { status: "waiting", output: result.output });
    81→        updateWorkflowRun(runId, {
    82→          status: "waiting",
    83→          context: ctx as Record<string, unknown>,
    84→        });
    85→        return; // Execution stops — resumed by event bus
    86→      }
    87→
    88→      // Instant node: mark completed, add output to context, continue
    89→      updateWorkflowRunStep(stepId, {
    90→        status: "completed",
    91→        output: result.output,
    92→        finishedAt: new Date().toISOString(),
    93→      });
    94→      ctx[node.id] = result.output;
    95→
    96→      const successors = getSuccessors(def, node.id, result.nextPort);
    97→      queue.push(...successors);
    98→    } catch (err) {
    99→      updateWorkflowRunStep(stepId, {
   100→        status: "failed",
   101→        error: String(err),
   102→        finishedAt: new Date().toISOString(),
   103→      });
   104→      updateWorkflowRun(runId, {
   105→        status: "failed",
   106→        error: String(err),
   107→        finishedAt: new Date().toISOString(),
   108→      });
   109→      return;
   110→    }
   111→  }
   112→
   113→  // No more nodes — workflow complete
   114→  const run = getWorkflowRun(runId);
