   123→
   124→async function executeNode(
   125→  node: WorkflowNode,
   126→  ctx: Record<string, unknown>,
   127→  runId: string,
   128→  stepId: string,
   129→): Promise<NodeResult> {
   130→  switch (node.type) {
   131→    // Trigger nodes pass through — they match during subscription, not execution
   132→    case "trigger-new-task":
   133→    case "trigger-task-completed":
   134→    case "trigger-webhook":
